#include <stdlib.h>
#include <stdio.h>
#include <stdint.h>
#include "murmurhash.h"
#if MURMURHASH_WANTS_HTOLE32
#define MURMURHASH_HAS_HTOLE32 1
#ifndef htole32
static uint32_t htole32 (uint32_t value) {
#if __BYTE_ORDER__ == __ORDER_BIG_ENDIAN__
  value = (
    ((value & 0xFF000000) >> 24) |
    ((value & 0x00FF0000) >> 8)  |
    ((value & 0x0000FF00) << 8)  |
    ((value & 0x000000FF) << 24)
  );
#endif
  return value;
}
#endif
#endif
uint32_t murmurhash (const char *key, uint32_t len, uint32_t seed) {
  uint32_t c1 = 0xcc9e2d51;
  uint32_t c2 = 0x1b873593;
  uint32_t r1 = 15;
  uint32_t r2 = 13;
  uint32_t m = 5;
  uint32_t n = 0xe6546b64;
  uint32_t h = 0;
  uint32_t k = 0;
  uint8_t *d = (uint8_t *) key; 
  const uint32_t *chunks = NULL;
  const uint8_t *tail = NULL; 
  int i = 0;
  int l = len / 4; 
  h = seed;
  chunks = (const uint32_t *) (d + l * 4); 
  tail = (const uint8_t *) (d + l * 4); 

  for (i = -l; i != 0; ++i) {

  #if MURMURHASH_HAS_HTOLE32
    k = htole32(chunks[i]);
  #else
    k = chunks[i];
  #endif

    k *= c1;
    k = (k << r1) | (k >> (32 - r1));
    k *= c2;

    h ^= k;
    h = (h << r2) | (h >> (32 - r2));
    h = h * m + n;
  }
  k = 0;

  switch (len & 3) { 
    case 3: k ^= (tail[2] << 16);
    case 2: k ^= (tail[1] << 8);
    case 1:
      k ^= tail[0];
      k *= c1;
      k = (k << r1) | (k >> (32 - r1));
      k *= c2;
      h ^= k;
  }
  h ^= len;
  h ^= (h >> 16);
  h *= 0x85ebca6b;
  h ^= (h >> 13);
  h *= 0xc2b2ae35;
  h ^= (h >> 16);
  return h;
}
